mapper.select:
SELECT i.inheritor_id AS inheritorId, i.name, i.project_id AS projectId, p.project_name AS projectName, i.years, i.intro, i.avatar FROM heritage_inheritor i INNER JOIN heritage_project p ON i.project_id = p.project_id
AND i.status = 1 AND p.status = 1
AND i.project_id = #{query.projectId}
AND i.name LIKE CONCAT('%', #{query.keyword}, '%')
ORDER BY i.inheritor_id DESC LIMIT #{query.size} OFFSET #{query.offset}
